import React, { useState } from "react";
import { Box, Button, TextField, Typography, Alert } from "@mui/material";
import { useNavigate } from "react-router-dom";
import { uploadRiderDocs } from "../services/api";

export default function UploadDocs() {
  const navigate = useNavigate();
  const [form, setForm] = useState({
    license: "",
    rc: "",
    insurance: "",
    photo: "",
    aadharFront: "",
    aadharBack: "",
  });
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const token = localStorage.getItem("token");

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  // 🔹 handle file upload (convert to base64 for now)
  const handleFileUpload = (e, field) => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      setForm({ ...form, [field]: reader.result });
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = async () => {
    try {
      const res = await uploadRiderDocs(token, form);
      if (res.data.success) {
        setMessage("✅ Documents uploaded successfully! Awaiting admin approval.");
        setError("");
        setTimeout(() => navigate("/rider-dashboard"), 1500);
      }
    } catch (err) {
      console.error("Upload error:", err);
      setError(err.response?.data?.message || "Error uploading documents");
    }
  };

  return (
    <Box sx={{ maxWidth: 500, mx: "auto", mt: 6 }}>
      <Typography variant="h4" sx={{ mb: 3, fontWeight: "bold" }}>
        Upload Documents
      </Typography>

      {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
      {message && <Alert severity="success" sx={{ mb: 2 }}>{message}</Alert>}

      <TextField fullWidth label="License Number" name="license" value={form.license} onChange={handleChange} sx={{ mb: 2 }} />
      <TextField fullWidth label="RC Number" name="rc" value={form.rc} onChange={handleChange} sx={{ mb: 2 }} />
      <TextField fullWidth label="Insurance Policy Number" name="insurance" value={form.insurance} onChange={handleChange} sx={{ mb: 2 }} />
      <TextField fullWidth label="Profile Photo URL" name="photo" value={form.photo} onChange={handleChange} sx={{ mb: 2 }} />

      {/* Aadhar Upload */}
      <Typography sx={{ mt: 2, mb: 1, fontWeight: "bold" }}>Aadhar Card (Front)</Typography>
      <input type="file" accept="image/*" capture="environment" onChange={(e) => handleFileUpload(e, "aadharFront")} />
      
      <Typography sx={{ mt: 2, mb: 1, fontWeight: "bold" }}>Aadhar Card (Back)</Typography>
      <input type="file" accept="image/*" capture="environment" onChange={(e) => handleFileUpload(e, "aadharBack")} />

      <Button
        variant="contained"
        sx={{ mt: 3, bgcolor: "black", color: "white", "&:hover": { bgcolor: "#333" } }}
        fullWidth
        onClick={handleSubmit}
      >
        Submit Documents
      </Button>
    </Box>
  );
}
